// n8n이 FastAPI ML API 3개의 결과를 수집·통합
const analysis  = $('【ML API①】AI 멀티에이전트 분석').first().json;
const portfolio = $('【ML API②】PPO 포트폴리오 최적화').first().json;
const ragQA     = $('【ML API③】RAG 리스크 Q&A').first().json;

// 시장 알림 조건 판단
const score  = analysis.sentimentScore || 0;
const grade  = (analysis.quality || {}).grade || '-';
const fng    = (analysis.marketData?.crypto?.fngValue) || 50;
const vix    = parseFloat((analysis.marketData?.indices?.vix?.price) || 20);
const isAlert = Math.abs(score) >= 30 || vix >= 30 || fng <= 20 || fng >= 80;

// 포트폴리오 상위 3개 자산
const weights = portfolio.weights || {};
const topAssets = Object.entries(weights)
  .sort(([,a],[,b]) => b - a)
  .slice(0, 3)
  .map(([k, v]) => `${k} ${(v*100).toFixed(0)}%`)
  .join(' | ');

// 최종 리포트 (웹UI 표시용)
const report = {
  date:           new Date().toLocaleString('ko-KR'),
  sentimentScore: score,
  sentimentLabel: analysis.sentimentLabel,
  grade,
  qualityScore:   (analysis.quality || {}).score,
  summary:        analysis.summary || '',
  mainAnalysis:   analysis.finalAnalysis || analysis.mainAnalysis || '',
  riskAnalysis:   analysis.riskAnalysis || '',
  ragAdvice:      ragQA.answer || '',
  portfolio: {
    weights:     weights,
    topAssets,
    voiceSummary: portfolio.voice_summary || '',
  },
  isAlert,
  alertReason: isAlert ? [
    Math.abs(score) >= 30 ? `심리점수 ${score}점` : '',
    vix >= 30             ? `VIX ${vix}` : '',
    fng <= 20             ? `극도 공포 FNG ${fng}` : '',
    fng >= 80             ? `극도 탐욕 FNG ${fng}` : '',
  ].filter(Boolean).join(', ') : ''
};

console.log(`✅ ML API 3개 결과 통합 완료 | 심리점수: ${score} | 등급: ${grade} | 알림: ${isAlert}`);
return [{ json: report }];

// 긴급 알림 포맷팅 (웹UI SSE 알림)
const d = $json;
const emoji = d.sentimentScore >= 30 ? '🟢' : d.sentimentScore <= -30 ? '🔴' : '🟡';

console.log(`🚨 긴급 알림 전송: ${d.alertReason}`);
return [{ json: {
  type: 'urgent_alert',
  title: `${emoji} 긴급 시장 알림`,
  message: `심리점수 ${d.sentimentScore}점 (${d.sentimentLabel}) | ${d.alertReason}`,
  sentimentScore: d.sentimentScore,
  portfolio: d.portfolio.topAssets,
  timestamp: new Date().toISOString()
}}];

const err = $json;
console.error('❌ V-Invest 파이프라인 오류:', JSON.stringify(err).substring(0, 200));
return [{ json: { type: 'pipeline_error', error: String(err.error || err), timestamp: new Date().toISOString() } }];
